// Chat Gateway Server
const connections = new Map(); // userId -> WebSocket

wss.on('connection', (ws, req) => {
  const userId = authenticateFromToken(req);
  connections.set(userId, ws);
  presenceService.setOnline(userId);

  ws.on('message', async (data) => {
    const msg = JSON.parse(data);

    switch (msg.type) {
      case 'SEND_MESSAGE': {
        // 1. Store message in DB
        const saved = await messageService.save({
          id: generateId(),
          senderId: userId,
          chatId: msg.chatId,
          content: msg.content,
          timestamp: Date.now(),
          status: 'SENT'
        });

        // 2. Get recipients
        const members = await chatService.getMembers(msg.chatId);

        // 3. Deliver to online users
        for (const memberId of members) {
          const recipientWs = connections.get(memberId);
          if (recipientWs?.readyState === WebSocket.OPEN) {
            recipientWs.send(JSON.stringify({
              type: 'NEW_MESSAGE',
              message: saved
            }));
          } else {
            // 4. Queue for offline delivery + push notification
            await notificationQueue.push(memberId, saved);
          }
        }
        break;
      }

      case 'TYPING':
        broadcastToChat(msg.chatId, userId, { type: 'TYPING', userId });
        break;

      case 'READ_RECEIPT':
        await messageService.markRead(msg.messageId, userId);
        break;
    }
  });

  ws.on('close', () => {
    connections.delete(userId);
    presenceService.setOffline(userId);
  });
});

// Presence service using Redis
class PresenceService {
  async setOnline(userId) {
    // Set user as online with 30s TTL
    await redis.set(`presence:${userId}`, 'online', 'EX', 30);
    // Heartbeat extends TTL every 10s from client
  }

  async setOffline(userId) {
    await redis.del(`presence:${userId}`);
    await redis.set(`last_seen:${userId}`, Date.now());
  }

  async getStatus(userId) {
    const online = await redis.get(`presence:${userId}`);
    if (online) return { status: 'online' };

    const lastSeen = await redis.get(`last_seen:${userId}`);
    return { status: 'offline', lastSeen };
  }

  // Batch check for contact list
  async getBulkStatus(userIds) {
    const pipeline = redis.pipeline();
    userIds.forEach(id => pipeline.get(`presence:${id}`));
    const results = await pipeline.exec();
    return userIds.map((id, i) => ({
      userId: id,
      online: results[i][1] === 'online'
    }));
  }
}

class TokenBucket {
  constructor(capacity, refillRate) {
    this.capacity = capacity;     // max tokens
    this.tokens = capacity;       // current tokens
    this.refillRate = refillRate; // tokens per second
    this.lastRefill = Date.now();
  }

  tryConsume() {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return true;  // request allowed
    }
    return false;   // rate limited
  }

  refill() {
    const now = Date.now();
    const elapsed = (now - this.lastRefill) / 1000;
    this.tokens = Math.min(
      this.capacity,
      this.tokens + elapsed * this.refillRate
    );
    this.lastRefill = now;
  }
}

// Usage: 10 requests/second, burst up to 20
const limiter = new TokenBucket(20, 10);

app.use((req, res, next) => {
  if (limiter.tryConsume()) {
    next();
  } else {
    res.status(429).json({
      error: 'Too Many Requests',
      retryAfter: Math.ceil(1 / limiter.refillRate)
    });
  }
});

// Sliding window counter using Redis
async function slidingWindowRateLimit(userId, limit, windowSec) {
  const now = Date.now();
  const windowStart = now - windowSec * 1000;
  const key = `ratelimit:${userId}`;

  // Use Redis sorted set with timestamps as scores
  const multi = redis.multi();

  // Remove expired entries
  multi.zremrangebyscore(key, 0, windowStart);

  // Count requests in current window
  multi.zcard(key);

  // Add current request
  multi.zadd(key, now, `${now}:${Math.random()}`);

  // Set expiry on the key
  multi.expire(key, windowSec);

  const results = await multi.exec();
  const requestCount = results[1][1];

  return {
    allowed: requestCount < limit,
    remaining: Math.max(0, limit - requestCount - 1),
    resetAt: new Date(now + windowSec * 1000)
  };
}

// Middleware
app.use(async (req, res, next) => {
  const result = await slidingWindowRateLimit(
    req.ip, 100, 60  // 100 requests per 60 seconds
  );

  res.set('X-RateLimit-Limit', '100');
  res.set('X-RateLimit-Remaining', result.remaining);
  res.set('X-RateLimit-Reset', result.resetAt.toISOString());

  if (!result.allowed) {
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }
  next();
});

// Different limits for different tiers and endpoints
const RATE_LIMITS = {
  free: {
    global: { limit: 100, window: 3600 },    // 100/hour
    search: { limit: 10, window: 60 },        // 10/min
    upload: { limit: 5, window: 3600 }        // 5/hour
  },
  premium: {
    global: { limit: 1000, window: 3600 },   // 1000/hour
    search: { limit: 60, window: 60 },        // 60/min
    upload: { limit: 50, window: 3600 }       // 50/hour
  }
};

function rateLimitMiddleware(action) {
  return async (req, res, next) => {
    const tier = req.user?.plan || 'free';
    const config = RATE_LIMITS[tier][action];
    const key = `${req.user?.id || req.ip}:${action}`;

    const result = await slidingWindowRateLimit(
      key, config.limit, config.window
    );

    if (!result.allowed) {
      return res.status(429).json({
        error: `Rate limit exceeded for ${action}`,
        retryAfter: config.window,
        upgrade: tier === 'free'
          ? 'Upgrade to premium for higher limits'
          : undefined
      });
    }
    next();
  };
}

// Apply per-route
app.get('/api/search', rateLimitMiddleware('search'), searchHandler);
app.post('/api/upload', rateLimitMiddleware('upload'), uploadHandler);

// Notification service flow
// 1. Event occurs -> 2. Build notification -> 3. Route to channels

class NotificationService {
  async send(event) {
    // 1. Get user preferences
    const prefs = await userPrefsStore.get(event.userId);

    // 2. Check if user wants this type
    if (!prefs.enabled[event.type]) return;

    // 3. Check quiet hours
    if (this.isQuietHours(prefs)) {
      await delayQueue.schedule(event, prefs.quietEnd);
      return;
    }

    // 4. Render template
    const content = await templateEngine.render(
      event.template,
      event.data
    );

    // 5. Route to enabled channels
    const channels = prefs.channels[event.type] || ['in_app'];

    for (const channel of channels) {
      await messageQueue.publish(`notifications.${channel}`, {
        userId: event.userId,
        content,
        priority: event.priority || 'normal',
        dedupeKey: `${event.type}:${event.userId}:${event.entityId}`
      });
    }
  }
}

