  const deathInfo = msg.properties.headers['x-death'];

  await db.failedMessages.create({
    queue: 'email_queue',
    payload: data,
    reason: deathInfo?.[0]?.reason || 'unknown',
    failedAt: new Date(),
    retryCount: deathInfo?.[0]?.count || 0
  });

