    // Add all prefixes to sorted sets
    for (let i = 1; i <= normalized.length; i++) {
      const prefix = normalized.substring(0, i);
      await redis.zincrby(
        `autocomplete:${prefix}`,
        count,
        normalized
      );
    }
  }

  // Trim to top 10 per prefix and set TTL
  // (done in batch job)
}

